// src/TravelHistory.jsx
import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";

const apiBase = "https://prasa-app-yde3.onrender.com";
const green = "#0f9d58";
const lightGreen = "#eaf8f0";

export default function TravelHistory({ employee }) {
  const navigate = useNavigate();
  const [travelExpenses, setTravelExpenses] = useState([]);
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");

  useEffect(() => {
    if (employee) fetchData();
  }, [employee]);

  const fetchData = async () => {
    const empId = employee.empId || employee.empld;

    const res = await fetch(
      `${apiBase}/travel-expenses?empId=${encodeURIComponent(empId)}`
    );

    const data = await res.json();
    console.log("TRAVEL RESPONSE:", data);

    setTravelExpenses(Array.isArray(data) ? data : []);
  };

  const filtered = travelExpenses.filter((t) => {
    const d = t.travel_date?.split?.("T")?.[0] || t.travel_date;
    if (startDate && d < startDate) return false;
    if (endDate && d > endDate) return false;
    return true;
  });

  const deleteTravel = async (id) => {
    if (!window.confirm("Delete travel entry?")) return;

    const res = await fetch(`${apiBase}/travel-expenses/${id}`, {
      method: "DELETE",
    });

    const data = await res.json();
    if (data.success) {
      setTravelExpenses((prev) => prev.filter((x) => x.id !== id));
    }
  };

  const editTravel = async (row) => {
    const newDate =
      window.prompt("Date:", row.travel_date?.split?.("T")?.[0]) ||
      row.travel_date;

    const newPurpose =
      window.prompt("Purpose:", row.purpose) || row.purpose;

    const newFrom =
      window.prompt("From:", row.location_from) || row.location_from;

    const newTo =
      window.prompt("To:", row.location_to) || row.location_to;

    const newAmount =
      window.prompt("Amount:", row.amount) || row.amount;

    const res = await fetch(`${apiBase}/travel-expenses/${row.id}`, {
      method: "PUT",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        travel_date: newDate,
        purpose: newPurpose,
        location_from: newFrom,
        location_to: newTo,
        amount: newAmount,
      }),
    });

    const data = await res.json();

    if (data.success) {
      setTravelExpenses((prev) =>
        prev.map((t) =>
          t.id === row.id
            ? {
                ...t,
                travel_date: newDate,
                purpose: newPurpose,
                location_from: newFrom,
                location_to: newTo,
                amount: newAmount,
              }
            : t
        )
      );
    }
  };

  return (
    <div style={outer}>
      <div style={card}>
        <div style={headerRow}>
          <button style={backBtn} onClick={() => navigate("/history")}>⬅ Back</button>
          <h2 style={title}>Travel Expense History</h2>
        </div>

        <p style={empInfo}>
          {employee.name} • {employee.empId || employee.empld}
        </p>

        {/* Filters */}
        <div style={filterBar}>
          <div>
            <span>From</span>
            <input
              type="date"
              value={startDate}
              onChange={(e) => setStartDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <div>
            <span>To</span>
            <input
              type="date"
              value={endDate}
              onChange={(e) => setEndDate(e.target.value)}
              style={filterInput}
            />
          </div>

          <button
            onClick={() => {
              setStartDate("");
              setEndDate("");
            }}
            style={clearBtn}
          >
            Clear
          </button>
        </div>

        <table style={table}>
          <thead>
            <tr>
              <th>Date</th>
              <th>Purpose</th>
              <th>Amount</th>
              <th>From</th>
              <th>To</th>
              <th>Action</th>
            </tr>
          </thead>

          <tbody>
            {filtered.map((t) => (
              <tr key={t.id}>
                <td>{t.travel_date?.split?.("T")?.[0]}</td>
                <td>{t.purpose}</td>
                <td>₹{t.amount}</td>
                <td>{t.location_from}</td>
                <td>{t.location_to}</td>
                <td>
                  <button style={editBtn} onClick={() => editTravel(t)}>Edit</button>
                  <button style={delBtn} onClick={() => deleteTravel(t.id)}>Delete</button>
                </td>
              </tr>
            ))}

            {filtered.length === 0 && (
              <tr>
                <td colSpan="6" style={noData}>No records found.</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}
